    public static function filterMenuItems($items)
    {
        if (!auth()->check()) {
            return [];
        }

        $filtered = [];
        $user = auth()->user();

        foreach ($items as $item) {
            if (isset($item['permission']) && !$user->can($item['permission'])) {
                continue;
            }
            $filtered[] = $item;
        }

        return $filtered;
    }

    public static function getMenuGroups()
    {
        $groups = [
            [
                'title' => 'Menu',
                'items' => self::filterMenuItems(self::getMainNavItems())
            ],
            [
                'title' => 'Caja / Ventas',
                'items' => self::filterMenuItems(self::getCajaNavItems())
            ],
            [
                'title' => 'Compras',
                'items' => self::filterMenuItems(self::getComprasNavItems())
            ],
            [
                'title' => 'Facturación (DIAN)',
                'items' => self::filterMenuItems(self::getFacturacionNavItems())
            ],
            [
                'title' => 'Gastos',
                'items' => self::filterMenuItems(self::getGastosNavItems())
            ],
            [
                'title' => 'Inventario',
                'items' => self::filterMenuItems(self::getInventarioNavItems())
            ],
            [
                'title' => 'Clientes',
                'items' => self::filterMenuItems(self::getClientesNavItems())
            ],
            [
                'title' => 'Configuración POS',
                'items' => self::filterMenuItems(self::getPosNavItems())
            ],

            /*
            [
                'title' => 'Others',
                'items' => self::filterMenuItems(self::getOthersItems())
            ],
            */
        ];

        // Solo retornar grupos que tengan al menos un item
        return array_filter($groups, function ($group) {
            return count($group['items']) > 0;
        });
    }

    public static function isActive($path)
    {
        return request()->is(ltrim($path, '/'));
    }

